//RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon160_FreteBaseCalculoIPI, &TCon160_FreteBaseCalculoIPI) //RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon144_FreteBaseCalculoICMS, &TCon144_FreteBaseCalculoICMS) //FRETE
//Valores que precisam ser preenchidos para realizar os calculos no sdtImpostoProduto //ValorTotalProduto //ProBasVlrIpi //ProBasVlrIcm //ProBasVlrIcmSt //ProBasPis //ProBasCofins //ProVlrFrt //ProVlrOut
//validacao a fazer. se informar //if &ImpAlqIcmStUF > 0 // &ImpAlqIcmExt = 0 // Endif
Do CAse CAse &sdtCadastroTabelaImpostoCbs.Tipo = 'CTE' &ValorBaseIbsCbs = &sdtImpostoProduto.ProVlrFrt &sdtImpostoProduto.ProVlrFrt = 0
Otherwise //BASE IBS (soma total produto, + frete, + outros valores + Seguro &ValorBaseIbsCbs = (&sdtImpostoProduto.ValorTotalProduto + &sdtImpostoProduto.ProVlrFrt + &sdtImpostoProduto.ProVlrOut)
//CONFORME ORIENTADO POR FERNANDA -- REAL CONTABILIDADE> PRIMEIRO ADICIONA O FRETE DEPOIS REDUZ if &sdtImpostoProduto.ProVlrFrt > 0 and &sdtImpostoProduto.ProBasVlrIpi > 0 and &sdtCadastroTabelaImpostoCbs.TCon160_FreteBaseCalculoIPI = 'S'//ACRESCENTA O //FRETE &sdtImpostoProduto.ProBasVlrIpi += &sdtImpostoProduto.ProVlrFrt Endif
//IPI &sdtImpostoProduto.ProVlrIpi = 0 If &sdtCadastroTabelaImpostoCbs.CImpIPI <> 0 &sdtImpostoProduto.ProVlrIpi = round((&sdtImpostoProduto.ProBasVlrIpi * &sdtCadastroTabelaImpostoCbs.CImpIPI) / 100,2) EndIF
Do Case CAse &sdtCadastroTabelaImpostoCbs.CImpIncIPI = 'S' and &sdtImpostoProduto.ProBasVlrIcmSt > 0 and &sdtCadastroTabelaImpostoCbs.CImpAlqIcmExt > 0 //INCLUIR NA BASE DO ICMS ST &sdtImpostoProduto.ProBasVlrIcmSt += &sdtImpostoProduto.ProVlrIpi CAse &sdtCadastroTabelaImpostoCbs.CImpIncIPI = 'I' and &sdtImpostoProduto.ProBasVlrIcm > 0 and &sdtCadastroTabelaImpostoCbs.CImpAlqIcmInt > 0 //INCLUIR IPI NA BASE DO ICMS &sdtImpostoProduto.ProBasVlrIcm += &sdtImpostoProduto.ProVlrIpi //JDF SOMA O IPI NA BASE DO ICMS, config EndCase
//CONFORME ORIENTADO POR FERNANDA -- REAL CONTABILIDADE> PRIMEIRO ADICIONA O FRETE DEPOIS REDUZ if &sdtImpostoProduto.ProVlrFrt > 0 and &sdtImpostoProduto.ProBasVlrIcm > 0 and (&sdtCadastroTabelaImpostoCbs.TCon144_FreteBaseCalculoICMS = 'A')//ACRESCENTA O //FRETE ANTES &sdtImpostoProduto.ProBasVlrIcm += &sdtImpostoProduto.ProVlrFrt Endif
&BaseIcmsAntesReducao = &sdtImpostoProduto.ProBasVlrIcm
//ICMS If not &sdtCadastroTabelaImpostoCbs.CImpAlqIcmInt.IsEmpty() if &sdtCadastroTabelaImpostoCbs.CImpRedAlqIcmInt > 0 //APLICA REDUCAO DO ICMS &sdtImpostoProduto.ProBasVlrIcm = &sdtImpostoProduto.ProBasVlrIcm - ((&sdtImpostoProduto.ProBasVlrIcm * &sdtCadastroTabelaImpostoCbs.CImpRedAlqIcmInt) / 100) EndIF Else &sdtImpostoProduto.ProBasVlrIcm = 0 EndIF
if &sdtImpostoProduto.ProVlrFrt > 0 and &sdtImpostoProduto.ProBasVlrIcm > 0 and (&sdtCadastroTabelaImpostoCbs.TCon144_FreteBaseCalculoICMS = 'S')//ACRESCENTA O //FRETE &sdtImpostoProduto.ProBasVlrIcm += &sdtImpostoProduto.ProVlrFrt &BaseIcmsAntesReducao += &sdtImpostoProduto.ProVlrFrt Endif
//R$ ICMS &sdtImpostoProduto.ProVlrIcm = 0 if &sdtImpostoProduto.ProBasVlrIcm <> 0 and &sdtCadastroTabelaImpostoCbs.CImpAlqIcmInt <> 0 &sdtImpostoProduto.ProVlrIcm = round((&sdtImpostoProduto.ProBasVlrIcm * &sdtCadastroTabelaImpostoCbs.CImpAlqIcmInt) / 100,2) Endif
//DIFERIMENTO if &sdtCadastroTabelaImpostoCbs.CImpDif > 0 and &sdtImpostoProduto.ProVlrIcm > 0 //Valor da Mercadoria - R$ 1.000,00 (a) //Alíquota do ICMS - 18% (b) //Valor do ICMS da operação - (18% de R$ 1.000,00) R$ 180,00 (c) = (a) x (b) //Percentual do ICMS diferido - (hipótese do inciso I, do Art. 96 do RICMS/PR) 33,33% (d) //Valor do ICMS diferido - (33,33% de R$ 180,00) R$ 60,00 (e) = (c) x (d) //Valor do ICMS devido - (R$ 180,00 – R$ 60,00) R$ 120,00 (f) = (c) – (d)
&sdtImpostoProduto.ProVlrDif = round((&sdtImpostoProduto.ProVlrIcm * &sdtCadastroTabelaImpostoCbs.CImpDif) / 100 , 2)
&sdtImpostoProduto.ProVlrIcm = &sdtImpostoProduto.ProVlrIcm - &sdtImpostoProduto.ProVlrDif EndIF
if &sdtCadastroTabelaImpostoCbs.CImpIcmsMotDes <> '' //caso tenha desoneracao do icms. &sdtImpostoProduto.ProBasVlrIcmSt = &sdtImpostoProduto.ProBasVlrIcmSt-&sdtImpostoProduto.ProVlrIcm Endif
//BASE DO ICMS ST.; Do CAse Case not &sdtCadastroTabelaImpostoCbs.CImpAlqIcmExt.IsEmpty() //and &NfsIcmAcreBca <> 0 If &sdtCadastroTabelaImpostoCbs.CImpRedAlqIcmExt <> 0 &sdtImpostoProduto.ProBasVlrIcmSt = &sdtImpostoProduto.ProBasVlrIcmSt - ((&sdtImpostoProduto.ProBasVlrIcmSt * &sdtCadastroTabelaImpostoCbs.CImpRedAlqIcmExt) / 100) EndIf
If &sdtCadastroTabelaImpostoCbs.CImpAlqMVA <> 0 &sdtImpostoProduto.ProBasVlrIcmSt = &sdtImpostoProduto.ProBasVlrIcmSt + ((&sdtImpostoProduto.ProBasVlrIcmSt * &sdtCadastroTabelaImpostoCbs.CImpAlqMVA)/100) EndIF
CAse not &sdtCadastroTabelaImpostoCbs.CImpAlqIcmStUF.IsEmpty() &sdtImpostoProduto.ProBasVlrIcmSt = &BaseIcmsAntesReducao
Otherwise &sdtImpostoProduto.ProBasVlrIcmSt = 0 EndCAse &sdtImpostoProduto.ProBasVlrIcmSt = round(&sdtImpostoProduto.ProBasVlrIcmSt, 2)
//Valor do icms st &sdtImpostoProduto.ProVlrIcmSt = 0 Do Case Case &sdtImpostoProduto.ProBasVlrIcmSt <> 0 and &sdtCadastroTabelaImpostoCbs.CImpAlqIcmExt <> 0 &sdtImpostoProduto.ProVlrIcmSt = round(((&sdtImpostoProduto.ProBasVlrIcmSt * &sdtCadastroTabelaImpostoCbs.CImpAlqIcmExt) / 100) - &sdtImpostoProduto.ProVlrIcm, 2)
Case &sdtImpostoProduto.ProBasVlrIcmSt <> 0 and &sdtCadastroTabelaImpostoCbs.CImpAlqIcmStUF <> 0 &sdtImpostoProduto.ProVlrIcmSt = round(((&sdtImpostoProduto.ProBasVlrIcmSt * &sdtCadastroTabelaImpostoCbs.CImpAlqIcmStUF) / 100), 2) EndCase
//FECOP &sdtImpostoProduto.ProVlrFCPIcmsSt = 0 if &sdtCadastroTabelaImpostoCbs.CImpTaxFecop > 0 and &sdtImpostoProduto.ProVlrIcmSt > 0 &sdtImpostoProduto.ProBasFCPIcmsSt = &sdtImpostoProduto.ProBasVlrIcmSt &sdtImpostoProduto.ProVlrFCPIcmsSt = round(&sdtImpostoProduto.ProBasFCPIcmsSt * (&sdtCadastroTabelaImpostoCbs.CImpTaxFecop/100),2) EndIf
//PIS if &sdtCadastroTabelaImpostoCbs.CImpExcPisCofins = 'S' //EXCLUIR VALOR DO ICMS //FERNANDA E FABIANO, SUGERIO PRIMEIRO DIMINUIR O ICMS E DEPOIS REDUZIR A BASE &sdtImpostoProduto.ProBasPis = &sdtImpostoProduto.ProBasPis - &sdtImpostoProduto.ProVlrIcm Endif if &sdtCadastroTabelaImpostoCbs.CImpPisRed > 0 &sdtImpostoProduto.ProBasPis = &sdtImpostoProduto.ProBasPis - ((&sdtImpostoProduto.ProBasPis * &sdtCadastroTabelaImpostoCbs.CImpPisRed) / 100) Endif
&sdtImpostoProduto.ProVlrPIS = 0 If &sdtCadastroTabelaImpostoCbs.CImpPis > 0 &sdtImpostoProduto.ProVlrPIS = round((&sdtImpostoProduto.ProBasPis * &sdtCadastroTabelaImpostoCbs.CImpPis) / 100, 2) EndIF
//COFINS if &sdtCadastroTabelaImpostoCbs.CImpExcPisCofins = 'S' //EXCLUIR VALOR DO ICMS //FERNANDA E FABIANO, SUGERIO PRIMEIRO DIMINUIR O ICMS E DEPOIS REDUZIR A BASE &sdtImpostoProduto.ProBasCofins = &sdtImpostoProduto.ProBasCofins - &sdtImpostoProduto.ProVlrIcm Endif if &sdtCadastroTabelaImpostoCbs.CImpCofinsRed > 0 &sdtImpostoProduto.ProBasCofins = &sdtImpostoProduto.ProBasCofins - ((&sdtImpostoProduto.ProBasCofins * &sdtCadastroTabelaImpostoCbs.CImpCofinsRed) / 100) Endif
&sdtImpostoProduto.ProVlrCOFINS = 0 If &sdtCadastroTabelaImpostoCbs.CImpCofins > 0 &sdtImpostoProduto.ProVlrCOFINS = round((&sdtImpostoProduto.ProBasCofins * &sdtCadastroTabelaImpostoCbs.CImpCofins) / 100, 2) EndIF
//calcular a base para o ibs e cbs. sem os impostos acima. //diminuir ICMS, ST, IPI, PIS, COFINS
&ValorBaseIbsCbs -= (&sdtImpostoProduto.ProVlrIcm + &sdtImpostoProduto.ProVlrIcmSt + &sdtImpostoProduto.ProVlrIpi + &sdtImpostoProduto.ProVlrPis + &sdtImpostoProduto.ProVlrCofins) EndCase
if &sdtCadastroTabelaImpostoCbs.Cltind_gIBSCBS = 'S' &sdtImpostoProduto.ValorBaseIbsCbs = &ValorBaseIbsCbs //so preencher se precisar destacar gIBSCBS Endif
if &sdtCadastroTabelaImpostoCbs.CltClsTipAliq = TipoAliquotaIbsCbs.SemAliquota &sdtImpostoProduto.ValorBaseIbsCbs = 0
//IBS UF E Mun &sdtImpostoProduto.ValorIbsMun = 0 &sdtImpostoProduto.ValorIbsUf = 0
//CBS (uniao) &sdtImpostoProduto.ValorCbs = 0 Else &sdtImpostoProduto.ValorBaseIbsCbs = &ValorBaseIbsCbs //so preencher se tivver aliquota
//IBS UF E Mun &sdtImpostoProduto.ValorIbsMun = &sdtImpostoProduto.ValorBaseIbsCbs * (&sdtCadastroTabelaImpostoCbs.ibsMunTaxEfe*0.01) &sdtImpostoProduto.ValorIbsUf = &sdtImpostoProduto.ValorBaseIbsCbs * (&sdtCadastroTabelaImpostoCbs.IbsUfTaxEfe*0.01)
//CBS (uniao) &sdtImpostoProduto.ValorCbs = &sdtImpostoProduto.ValorBaseIbsCbs * (&sdtCadastroTabelaImpostoCbs.IbsUnTaxEfe*0.01) Endif
//diferimento if &sdtCadastroTabelaImpostoCbs.CltIsDif = 'S' //Diferido &sdtImpostoProduto.NfeIbsUfVlrDif = &sdtImpostoProduto.ValorIbsUf * (&sdtCadastroTabelaImpostoCbs.NfeIbsUfPerDif*0.01) &sdtImpostoProduto.NfeIbsMunVlrDif = &sdtImpostoProduto.ValorIbsMun * (&sdtCadastroTabelaImpostoCbs.NfeIbsMunPerDif*0.01) &sdtImpostoProduto.NfeCbsVlrDif = &sdtImpostoProduto.ValorCbs * (&sdtCadastroTabelaImpostoCbs.NfeCbsPerDif*0.01)
&sdtImpostoProduto.ValorIbsMun -= &sdtImpostoProduto.NfeIbsMunVlrDif &sdtImpostoProduto.ValorIbsUf -= &sdtImpostoProduto.NfeIbsUfVlrDif &sdtImpostoProduto.ValorCbs -= &sdtImpostoProduto.NfeCbsVlrDif //diminui o valor do diferimento Endif
//aliquota regular if &sdtCadastroTabelaImpostoCbs.CltClsIsTribReg = 'S' &sdtImpostoProduto.ValorBaseIbsCbs = &ValorBaseIbsCbs //so preenche se exigir tributacao regular
//IBS UF E Mun &sdtImpostoProduto.NfeRegIbsUfeVlr = &sdtImpostoProduto.ValorBaseIbsCbs * (&sdtCadastroTabelaImpostoCbs.NfeRegIbsUfeTaxEfe*0.01) &sdtImpostoProduto.NfeRegIbsMunVlr = &sdtImpostoProduto.ValorBaseIbsCbs * (&sdtCadastroTabelaImpostoCbs.NfeRegIbsMunTaxEfe*0.01)
//CBS (uniao) &sdtImpostoProduto.NfeRegCbsVlr = &sdtImpostoProduto.ValorBaseIbsCbs * (&sdtCadastroTabelaImpostoCbs.NfeRegCbsTaxEfe*0.01) EndIf

//parm(in:&TCon147_ExcluirIcmsPisCofins, in:&TCon145_IpiBaseCalculoICMS, in:&FilRegTrib, in:&SitCod, inout:&ImpAlqIcmInt, inout:&ImpRedAlqIcmInt, in:&ImpAlqIcmExt, in:&ImpRedAlqIcmExt, 
//	in:&ImpAlqMVA, in:&ImpIPI, in:&ImpCofins, in:&ImpPis, in:&ImpDif, in:&ImpPisRed, in:&ImpCofinsRed,
//	inout:&tmpProBasVlrIcm, out:&tmpProVlrIcm, 
//	inout:&tmpProBasVlrIcmSt, out:&tmpProVlrIcmSt, 
//	inout:&tmpProBasVlrIpi, out:&tmpProVlrIpi, inout:&tmpBasePIS, out:&tmpProVlrCOFINS,
////	inout:&tmpBaseConfins, out:&tmpProVlrPIS, out:&tmpProVlrDif);
//

parm(in:&sdtCadastroTabelaImpostoCbs, inout:&sdtImpostoProduto);
